import UIKit
import CryptoKit

class WalletViewController: UIViewController {

    var privateKey: Curve25519.Signing.PrivateKey?
    var publicKey: Curve25519.Signing.PublicKey?

    override func viewDidLoad() {
        super.viewDidLoad()
        generateKeyPair()
    }

    func generateKeyPair() {
        privateKey = Curve25519.Signing.PrivateKey()
        publicKey = privateKey?.publicKey
        
        // Save private key securely
        savePrivateKeyToKeychain(key: privateKey!.rawRepresentation)
    }

    func savePrivateKeyToKeychain(key: Data) {
        let keychainQuery: [String: Any] = [
            kSecClass as String: kSecClassKey,
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecAttrKeySizeInBits as String: 256,
            kSecValueData as String: key
        ]
        SecItemAdd(keychainQuery as CFDictionary, nil)
    }

    func signTransaction(transactionData: Data) -> Data? {
        guard let privateKey = privateKey else { return nil }
        let signature = try? privateKey.signature(for: transactionData)
        return signature?.rawRepresentation
    }

    func sendTransaction(signature: Data, transactionData: Data) {
        guard let url = URL(string: "https://yourblockchainapi.com/send") else { return }
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        let body: [String: Any] = [
            "transaction": transactionData.base64EncodedString(),
            "signature": signature.base64EncodedString()
        ]
        request.httpBody = try? JSONSerialization.data(withJSONObject: body)
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")

        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                print("Error sending transaction: \(error)")
                return
            }
            print("Transaction sent successfully")
        }
        task.resume()
    }
}